(364, 1, 'items_biblioteca', 1, 'INSERT', NULL, '{\"id\":\"\",\"portada\":\"\",\"titulo\":\"Industrialización de productos lácteos en la Hacienda Agusbella de la parroquia Rumipamba ubicada en el cantón Rumiñahui como resultado de la práctica preprofesional de los estudiantes de la Carrera de Producción Animal\",\"autor\":\"María José Jiménez\",\"revista\":\"\",\"anio\":\"2023\",\"descripcion\":\"Describe la experiencia de estudiantes de Producción Animal en la industrialización de productos lácteos en la Hacienda Agusbella. Se enfatiza la vinculación con productores locales, la aplicación de buenas prácticas de manufactura, leyes de sanitización y técnicas tradicionales, logrando cumplir los estándares de calidad del mercado.\\n\",\"categoria_id\":\"16\",\"link_archivo\":\"https:\\/\\/congreso.aitec.edu.ec\\/wp-content\\/uploads\\/2024\\/01\\/Memorias-del-I-Congreso-Internacional-AITEC-2023.pdf\",\"codigo\":\"2023-TEN-001\"}', '45.173.230.31', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/143.0.0.0 Safari/537.36 Edg/143.0.0.0', 'Creación de nueva publicación', '2026-01-06 21:00:00'),
