(378, 1, 'items_biblioteca', 1, 'INSERT', NULL, '{\"id\":\"\",\"portada\":\"\",\"titulo\":\"Formación Técnica y Tecnológica en Modalidad Híbrida “Estudio de Caso: Tecnología Superior en Cuidado Canino” del Instituto Superior Tecnológico Superarse\",\"autor\":\"Renee Nickole Jaramillo Uvidia , Karla Elizabeth Novoa Medina\",\"revista\":\"\",\"anio\":\"2022\",\"descripcion\":\"Este documento contiene las memorias del Encuentro Internacional de Formación Técnica y Tecnológica E-Tech 2022, incluyendo varios artículos sobre buenas prácticas en institutos superiores del Ecuador, así como conferencias presentadas. Los artículos cubren temas como competencias digitales, proyectos de vinculación comunitaria, marketing, sistemas móviles, aulas virtuales, emprendimiento, diseño y construcción de máquinas, entre otros. El documento fue editado por la Dirección de Estudios e Investigación del\",\"categoria_id\":\"22\",\"link_archivo\":\"https:\\/\\/es.scribd.com\\/document\\/704723871\\/Memorias-e-Tech-2022\",\"codigo\":\"2022-CUI-001\"}', '45.173.230.31', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/143.0.0.0 Safari/537.36 Edg/143.0.0.0', 'Creación de nueva publicación', '2026-01-06 21:44:41'),
