(537, NULL, 'items_biblioteca', 330, 'UPDATE', '{\"id\":330,\"tipo_id\":3,\"categoria_id\":22,\"codigo\":\"2022-CUI-001\",\"titulo\":\"Formación Técnica y Tecnológica en Modalidad Híbrida “Estudio de Caso: Tecnología Superior en Cuidado Canino” del Instituto Superior Tecnológico Superarse\",\"autor\":\"Renee Nickole Jaramillo Uvidia , Karla Elizabeth Novoa Medina\",\"descripcion\":\"Este documento contiene las memorias del Encuentro Internacional de Formación Técnica y Tecnológica E-Tech 2022, incluyendo varios artículos sobre buenas prácticas en institutos superiores del Ecuador, así como conferencias presentadas. Los artículos cubren temas como competencias digitales, proyectos de vinculación comunitaria, marketing, sistemas móviles, aulas virtuales, emprendimiento, diseño y construcción de máquinas, entre otros. El documento fue editado por la Dirección de Estudios e Investigación del\",\"portada\":\"\",\"edicion\":null,\"tutor\":null,\"universidad\":null,\"revista\":\"\",\"codigo_barra\":null,\"anio\":\"2022\",\"link_archivo\":\"https:\\/\\/es.scribd.com\\/document\\/704723871\\/Memorias-e-Tech-2022\",\"numero_ejemplares\":1,\"stock\":1,\"visitas\":0,\"fecha_ingreso\":\"2026-01-06\",\"estado\":\"ACTIVO\",\"created_at\":\"2026-01-06 16:44:41\",\"updated_at\":\"2026-01-06 16:44:41\",\"deleted_at\":null,\"ubicacion\":null}', '{\"id\":330,\"tipo_id\":3,\"categoria_id\":22,\"codigo\":\"2022-CUI-001\",\"titulo\":\"Formación Técnica y Tecnológica en Modalidad Híbrida “Estudio de Caso: Tecnología Superior en Cuidado Canino” del Instituto Superior Tecnológico Superarse\",\"autor\":\"Renee Nickole Jaramillo Uvidia , Karla Elizabeth Novoa Medina\",\"descripcion\":\"Este documento contiene las memorias del Encuentro Internacional de Formación Técnica y Tecnológica E-Tech 2022, incluyendo varios artículos sobre buenas prácticas en institutos superiores del Ecuador, así como conferencias presentadas. Los artículos cubren temas como competencias digitales, proyectos de vincula