(618, NULL, 'items_biblioteca', 324, 'UPDATE', '{\"id\":324,\"tipo_id\":3,\"categoria_id\":17,\"codigo\":\"2023-CAC-001\",\"titulo\":\"Formación técnica y tecnológica en modalidad híbrida \\\"Estudio de caso: Tecnología Superior en Cuidado Canino\\\" del ISTS\",\"autor\":\"Renee Jaramillo, Karla Novoa\",\"descripcion\":\"Analiza la adopción de la modalidad híbrida en el ISTS como respuesta a la pandemia, utilizando recursos tecnológicos y prácticas presenciales para garantizar la continuidad educativa y el cumplimiento del perfil profesional de los estudiantes.  \\n\",\"portada\":\"https:\\/\\/isbnecuador.com\\/files\\/titulos\\/96318.jpg\",\"edicion\":null,\"tutor\":null,\"universidad\":null,\"revista\":\"\",\"codigo_barra\":null,\"anio\":\"2023\",\"link_archivo\":\"https:\\/\\/www.caces.gob.ec\\/wp-content\\/uploads\\/Documents\\/PUBLICACIONES\\/MEMORIAS%20E%20TECH%202022%20r.pdf\",\"numero_ejemplares\":1,\"stock\":1,\"visitas\":0,\"fecha_ingreso\":\"2026-01-06\",\"estado\":\"ACTIVO\",\"created_at\":\"2026-01-06 16:19:27\",\"updated_at\":\"2026-01-06 16:19:27\",\"deleted_at\":null,\"ubicacion\":null}', '{\"id\":324,\"tipo_id\":3,\"categoria_id\":17,\"codigo\":\"2023-CAC-001\",\"titulo\":\"Formación técnica y tecnológica en modalidad híbrida \\\"Estudio de caso: Tecnología Superior en Cuidado Canino\\\" del ISTS\",\"autor\":\"Renee Jaramillo, Karla Novoa\",\"descripcion\":\"Analiza la adopción de la modalidad híbrida en el ISTS como respuesta a la pandemia, utilizando recursos tecnológicos y prácticas presenciales para garantizar la continuidad educativa y el cumplimiento del perfil profesional de los estudiantes.  \\n\",\"portada\":\"https:\\/\\/isbnecuador.com\\/files\\/titulos\\/96318.jpg\",\"edicion\":null,\"tutor\":null,\"universidad\":null,\"revista\":\"\",\"codigo_barra\":null,\"anio\":\"2023\",\"link_archivo\":\"https:\\/\\/www.caces.gob.ec\\/wp-content\\/uploads\\/Documents\\/PUBLICACIONES\\/MEMORIAS%20E%20TECH%202022%20r.pdf\",\"numero_ejemplares\":1,\"stock\":1,\"visitas\":1,\"fecha_ingreso\":\"2026-01-06\",\"estado\":\"ACTIVO\",\"created_at\":\"2026-01-06 16:19:27\",\"updated_at\":\"2026-01-27 16:02:01\",\"deleted_at\":null,\"ubicacion\":null}', '200.105.254.69', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:147.0) Gecko/20100101 Firefox/147.0', 'Incremento de visitas en publicación', '2026-01-27 21:02:01'),
(619, NULL, 'items_biblioteca', 323, 'UPDATE', '{\"id\":323,\"tipo_id\":3,\"categoria_id\":16,\"codigo\":\"2023-TEN-001\",\"titulo\":\"Industrialización de productos lácteos en la Hacienda Agusbella de la parroquia Rumipamba ubicada en el cantón Rumiñahui como resultado de la práctica preprofesional de los estudiantes de la Carrera de Producción Animal\",\"autor\":\"María José Jiménez\",\"descripcion\":\"Describe la experiencia de estudiantes de Producción Animal en la industrialización de productos lácteos en la Hacienda Agusbella. Se enfatiza la vinculación con productores locales, la aplicación de buenas prácticas de manufactura, leyes de sanitización y técnicas tradicionales, logrando cumplir los estándares de calidad del mercado.\\n\",\"portada\":\"https:\\/\\/drive.google.com\\/file\\/d\\/14bOdwX-yZqNwbIUEMT_EthfKvx09fUz1\\/view?usp=sharing\",\"edicion\":null,\"tutor\":null,\"universidad\":null,\"revista\":\"\",\"codigo_barra\":null,\"anio\":\"2023\",\"link_archivo\":\"https:\\/\\/congreso.aitec.edu.ec\\/wp-content\\/uploads\\/2024\\/01\\/Memorias-del-I-Congreso-Internacional-AITEC-2023.pdf\",\"numero_ejemplares\":1,\"stock\":1,\"visitas\":0,\"fecha_ingreso\":\"2026-01-06\",\"estado\":\"ACTIVO\",\"created_at\":\"2026-01-06 16:00:00\",\"updated_at\":\"2026-01-06 16:12:28\",\"deleted_at\":null,\"ubicacion\":null}', '{\"id\":323,\"tipo_id\":3,\"categoria_id\":16,\"codigo\":\"2023-TEN-001\",\"titulo\":\"Industrialización de productos lácteos en la Hacienda Agusbella de la parroquia Rumipamba ubicada en el cantón Rumiñahui como resultado de la práctica preprofesional de los estudiantes de la Carrera de Producción Animal\",\"autor\":\"María José Jiménez\",\"descripcion\":\"Describe la experiencia de estudiantes de Producción Animal en la industrialización de productos lácteos en la Hacienda Agusbella. Se enfatiza la vinculación con productores locales, la aplicación de buenas prácticas de manufactura, leyes de sanitización y técnicas tradicionales, logrando cumplir los estándares de calidad del mercado.\\n\",\"portada\":\"https:\\/\\/drive.google.com\\/file\\/d\\/14bOdwX-yZqNwbIUEMT_EthfKvx09fUz1\\/view?usp=sharing\",\"edicion\":null,\"tutor\":null,\"universidad\":null,\"revista\":\"\",\"codigo_barra\":null,\"anio\":\"2023\",\"link_archivo\":\"https:\\/\\/congreso.aitec.edu.ec\\/wp-content\\/uploads\\/2024\\/01\\/Memorias-del-I-Congreso-Internacional-AITEC-2023.pdf\",\"numero_ejemplares\":1,\"stock\":1,\"visitas\":1,\"fecha_ingreso\":\"2026-01-06\",\"estado\":\"ACTIVO\",\"created_at\":\"2026-01-06 16:00:00\",\"updated_at\":\"2026-01-27 16:02:04\",\"deleted_at\":null,\"ubicacion\":null}', '200.105.254.69', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:147.0) Gecko/20100101 Firefox/147.0', 'Incremento de visitas en publicación', '2026-01-27 21:02:04'),
