(323, 3, 16, '2023-TEN-001', 'Industrialización de productos lácteos en la Hacienda Agusbella de la parroquia Rumipamba ubicada en el cantón Rumiñahui como resultado de la práctica preprofesional de los estudiantes de la Carrera de Producción Animal', 'María José Jiménez', 'Describe la experiencia de estudiantes de Producción Animal en la industrialización de productos lácteos en la Hacienda Agusbella. Se enfatiza la vinculación con productores locales, la aplicación de buenas prácticas de manufactura, leyes de sanitización y técnicas tradicionales, logrando cumplir los estándares de calidad del mercado.\n', 'https://drive.google.com/file/d/14bOdwX-yZqNwbIUEMT_EthfKvx09fUz1/view?usp=sharing', NULL, NULL, NULL, '', NULL, '2023', 'https://congreso.aitec.edu.ec/wp-content/uploads/2024/01/Memorias-del-I-Congreso-Internacional-AITEC-2023.pdf', 1, 1, 1, '2026-01-06', 'ACTIVO', '2026-01-06 21:00:00', '2026-01-27 21:02:04', NULL, NULL),
(324, 3, 17, '2023-CAC-001', 'Formación técnica y tecnológica en modalidad híbrida \"Estudio de caso: Tecnología Superior en Cuidado Canino\" del ISTS', 'Renee Jaramillo, Karla Novoa', 'Analiza la adopción de la modalidad híbrida en el ISTS como respuesta a la pandemia, utilizando recursos tecnológicos y prácticas presenciales para garantizar la continuidad educativa y el cumplimiento del perfil profesional de los estudiantes.  \n', 'https://isbnecuador.com/files/titulos/96318.jpg', NULL, NULL, NULL, '', NULL, '2023', 'https://www.caces.gob.ec/wp-content/uploads/Documents/PUBLICACIONES/MEMORIAS%20E%20TECH%202022%20r.pdf', 1, 1, 2, '2026-01-06', 'ACTIVO', '2026-01-06 21:19:27', '2026-02-01 19:58:14', NULL, NULL),
(325, 3, 17, '2022-CAC-001', 'Industrialización de productos lácteos en la Hacienda Agusbella de la parroquia Rumipamba ubicada en el cantón Rumiñahui como resultado de la práctica preprofesional de los estudiantes de la Carrera de Producción Animal', 'María José Jiménez', 'Describe la experiencia de estudiantes de Producción Animal en la industrialización de productos lácteos en la Hacienda Agusbella.\n', 'https://imgv2-2-f.scribdassets.com/img/document/704723871/original/e5333a9669/1?v=1', NULL, NULL, NULL, '', NULL, '2022', 'https://www.caces.gob.ec/wp-content/uploads/Documents/PUBLICACIONES/MEMORIAS%20E%20TECH%202022%20r.pdf', 1, 1, 2, '2026-01-06', 'ACTIVO', '2026-01-06 21:24:41', '2026-02-02 15:11:12', NULL, NULL),
(326, 3, 18, '2024-PUB-001', 'Guía General de Estudio Publicidad Digital', 'Mgtr. Diego Proaño C.', 'Contenidos completos sobre publicidad digital: estrategias, herramientas, marketing en redes sociales y análisis de campañas para fortalecer competencias prácticas y teóricas.\n', 'https://isbnecuador.com/files/titulos/99423.jpg', NULL, NULL, NULL, 'Instituto Superior Tecnológico Superarse', NULL, '2024', 'https://isbnecuador.com/catalogo.php?mode=detalle&nt=99423', 1, 1, 2, '2026-01-06', 'ACTIVO', '2026-01-06 21:28:45', '2026-01-23 13:09:25', NULL, NULL),
