(328, 3, 20, '2024-HUM-001', 'Humanidades e Ciências Sociais — Capítulo 13: Hábitos de consumo en pagos electrónicos durante y después de la pandemia de COVID-19 en El Oro', 'PhD.(e) Renee Jaramillo, MSc. MVZ. Karla Novoa', 'Analiza cambios en hábitos de consumo mediante pagos electrónicos en El Oro durante y después de la pandemia, examinando adopción tecnológica y tendencias financieras.\n', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQbXS3qMBBSPF3fCdonkgSPAnk3S4nJsGXARFbn9kf_8A&s', NULL, NULL, NULL, 'EDITORA ARTEMIS', NULL, '2024', 'https://superarse.edu.ec/assets/docs/Investigacion/humanidades-e-ciencias-sociais-perspectivas.pdf', 1, 1, 2, '2026-01-06', 'ACTIVO', '2026-01-06 21:36:53', '2026-02-13 21:38:44', NULL, NULL),
(329, 3, 21, '2024-TOP-001', 'Técnicas y Procedimientos Aplicables a la Topografía Subterránea', 'Top. David Serrano, Ing. Andrés Sierra', 'Guía didáctica sobre topografía subterránea, combinando teoría, técnicas aplicadas y normativas, para proporcionar bases sólidas en proyectos subterráneos.\n', '', NULL, NULL, NULL, '', NULL, '2024', 'https://superarse.edu.ec/assets/docs/Investigacion/LIBRO_TOPOGRAFIA_SUBTERR%C3%81NEA.pdf', 1, 1, 3, '2026-01-06', 'ACTIVO', '2026-01-06 21:41:55', '2026-01-27 21:01:50', NULL, NULL),
(330, 3, 22, '2022-CUI-001', 'Formación Técnica y Tecnológica en Modalidad Híbrida “Estudio de Caso: Tecnología Superior en Cuidado Canino” del Instituto Superior Tecnológico Superarse', 'Renee Nickole Jaramillo Uvidia , Karla Elizabeth Novoa Medina', 'Este documento contiene las memorias del Encuentro Internacional de Formación Técnica y Tecnológica E-Tech 2022, incluyendo varios artículos sobre buenas prácticas en institutos superiores del Ecuador, así como conferencias presentadas. Los artículos cubren temas como competencias digitales, proyectos de vinculación comunitaria, marketing, sistemas móviles, aulas virtuales, emprendimiento, diseño y construcción de máquinas, entre otros. El documento fue editado por la Dirección de Estudios e Investigación del', '', NULL, NULL, NULL, '', NULL, '2022', 'https://es.scribd.com/document/704723871/Memorias-e-Tech-2022', 1, 1, 2, '2026-01-06', 'ACTIVO', '2026-01-06 21:44:41', '2026-01-27 21:01:52', NULL, NULL),
(331, 3, 17, '2022-CAC-002', 'Industrialización de productos lácteos en la Hacienda Agusbella de la parroquia Rumipamba ubicada en el cantón Rumiñahui como resultado de la práctica preprofesional de los estudiantes de la Carrera de Producción Animal.', ' María José Jiménez Arciniega , Iván René Pillajo Yujato, Fernanda Lizbeth Guanochanga Llumiugsi', 'El libro proporciona una visión general de la situación actual de la formación técnica y tecnológica\nen el país y presenta recomendaciones para mejorar la calidad y relevancia de la educación en este campo\nesencial.', 'https://imgv2-2-f.scribdassets.com/img/document/704723871/original/e5333a9669/1?v=1', NULL, NULL, NULL, '', NULL, '2022', 'https://www.caces.gob.ec/wp-content/uploads/Documents/PUBLICACIONES/MEMORIAS%20E%20TECH%202022%20r.pdf', 1, 1, 1, '2026-01-06', 'ACTIVO', '2026-01-06 21:46:59', '2026-02-11 13:45:50', '2026-02-11 13:45:50', NULL),
(332, 3, 17, '2022-CAC-003', 'Industrialización de productos lácteos en la Hacienda Agusbella de la parroquia Rumipamba ubicada en el cantón Rumiñahui como resultado de la práctica preprofesional de los estudiantes de la Carrera de Producción Animal.', ' María José Jiménez Arciniega , Iván René Pillajo Yujato, Fernanda Lizbeth Guanochanga Llumiugsi', 'Industrialización de productos lácteos en la Hacienda Agusbella de la parroquia Rumipamba ubicada en el cantón Rumiñahui como resultado de la práctica preprofesional de los estudiantes de la Carrera de Producción Animal.\n', 'https://imgv2-2-f.scribdassets.com/img/document/704723871/original/e5333a9669/1?v=1', NULL, NULL, NULL, '', NULL, '2022', 'https://www.caces.gob.ec/wp-content/uploads/Documents/PUBLICACIONES/MEMORIAS%20E%20TECH%202022%20r.pdf', 1, 1, 4, '2026-01-06', 'ACTIVO', '2026-01-06 21:49:56', '2026-02-11 13:43:17', NULL, NULL),
(333, 3, 23, '2024-DIV-001', 'PRIMER CONGRESO INTERNACIONAL DE INNOVACIÓN, TECNOLOGÍA, PATRIMONIO Y SOSTENIBILIDAD O.D.S. — Capítulo: Aprovechamiento del mucílago de cacao para elaboración de alcohol', 'César Andrés Ramírez Romero', 'Presenta el aprovechamiento del mucílago de cacao para producir alcohol, promoviendo economía circular mediante innovación tecnológica y procesos ecoeficientes.\n', 'https://yavirac.edu.ec/wp-content/uploads/2024/11/Congreso.png', NULL, NULL, NULL, '', NULL, '2024', 'https://superarse.edu.ec/assets/docs/Investigacion/2.Libro.pdf', 1, 1, 3, '2026-01-06', 'ACTIVO', '2026-01-06 21:52:51', '2026-02-14 18:30:04', NULL, NULL),
(334, 3, 23, '2024-DIV-002', 'Estudos em Ciências Agrárias e Ambientais — Capítulo: Industrialización de productos lácteos en Hacienda Agusbella', 'MSc. María José Jiménez, MSc. Nathaly Freire, MSc. Fabian Tello', 'Describe la industrialización de productos lácteos desarrollada por estudiantes de Producción Animal, resaltando impacto académico y productivo en la comunidad educativa.\n', 'https://th.bing.com/th/id/OIP.uORA2Wh_XOfwF5eSDP41XwAAAA?w=142&h=204&c=7&r=0&o=7&pid=1.7&rm=3', NULL, NULL, NULL, '', NULL, '2024', 'https://superarse.edu.ec/assets/docs/Investigacion/1.%20Libro.pdf', 1, 1, 1, '2026-01-06', 'ACTIVO', '2026-01-06 21:54:19', '2026-02-03 00:53:53', NULL, NULL),
